const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;

export const runScenario = (scenario: any): unknown => {
  const items = scenario?.steps?.[0]?.items ?? [];
  const basePremium = computeBasePremium(items);
  const itemSurcharges = computeItemSurcharges(items);
  const firstInsurance = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
  const years = scenario?.customer?.yearsWithMHPCO ?? 0;
  const loyaltyDiscount =
    years >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
  const premium =
    basePremium + itemSurcharges + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
  return { results: [{ premium }] };
};
